        code: "// JavaScript doesn't have a built-in heap,\n// but we can simulate a min-heap with an array\nclass MinHeap {\n  constructor() { this.heap = []; }\n  push(val) {\n    this.heap.push(val);\n    this._bubbleUp(this.heap.length - 1);\n  }\n  pop() {\n    const min = this.heap[0];\n    const last = this.heap.pop();\n    if (this.heap.length) { this.heap[0] = last; this._sinkDown(0); }\n    return min;\n  }\n  peek() { return this.heap[0]; }\n  size() { return this.heap.length; }\n  _bubbleUp(i) {\n    while (i > 0) {\n      const p = (i - 1) >> 1;\n      if (this.heap[p] <= this.heap[i]) break;\n      [this.heap[p], this.heap[i]] = [this.heap[i], this.heap[p]];\n      i = p;\n    }\n  }\n  _sinkDown(i) {\n    const n = this.heap.length;\n    while (true) {\n      let min = i, l = 2*i+1, r = 2*i+2;\n      if (l < n && this.heap[l] < this.heap[min]) min = l;\n      if (r < n && this.heap[r] < this.heap[min]) min = r;\n      if (min === i) break;\n      [this.heap[min], this.heap[i]] = [this.heap[i], this.heap[min]];\n      i = min;\n    }\n  }\n}\n// Kth largest: maintain min-heap of size k\nfunction kthLargest(nums, k) {\n  const h = new MinHeap();\n  for (const n of nums) { h.push(n); if (h.size() > k) h.pop(); }\n  return h.peek();\n}\nconsole.log(kthLargest([3,2,1,5,6,4], 2)); // 5",
