        code: "// Dijkstra with min-heap (simulated with sorted array)\nfunction dijkstra(n, edges, src) {\n  const adj = Array.from({length: n}, () => []);\n  for (const [u, v, w] of edges) {\n    adj[u].push([v, w]);\n    adj[v].push([u, w]); // undirected\n  }\n\n  const dist = new Array(n).fill(Infinity);\n  dist[src] = 0;\n\n  // Min-heap: [distance, node]\n  const heap = [[0, src]];\n\n  while (heap.length) {\n    heap.sort((a, b) => a[0] - b[0]); // sort by distance\n    const [d, u] = heap.shift();\n\n    if (d > dist[u]) continue; // stale entry\n\n    for (const [v, w] of adj[u]) {\n      if (dist[u] + w < dist[v]) {\n        dist[v] = dist[u] + w;\n        heap.push([dist[v], v]);\n      }\n    }\n  }\n  return dist;\n}\n\nconst edges = [[0,1,4],[0,2,1],[2,1,2],[1,3,1],[2,3,5]];\nconsole.log(dijkstra(4, edges, 0));\n// [0, 3, 1, 4] — shortest distances from node 0",
