        code: "// Climbing Stairs — how many ways to reach step n\n// (can take 1 or 2 steps at a time)\n\n// Naive recursion — O(2^n)\nfunction climbNaive(n) {\n  if (n <= 2) return n;\n  return climbNaive(n-1) + climbNaive(n-2);\n}\n\n// DP (bottom-up) — O(n)\nfunction climbDP(n) {\n  if (n <= 2) return n;\n  const dp = new Array(n + 1);\n  dp[1] = 1; dp[2] = 2;\n  for (let i = 3; i <= n; i++) dp[i] = dp[i-1] + dp[i-2];\n  return dp[n];\n}\nconsole.log(climbDP(10)); // 89\n\n// Space-optimized — O(1) space\nfunction climbOpt(n) {\n  if (n <= 2) return n;\n  let prev2 = 1, prev1 = 2;\n  for (let i = 3; i <= n; i++) {\n    const curr = prev1 + prev2;\n    prev2 = prev1;\n    prev1 = curr;\n  }\n  return prev1;\n}\nconsole.log(climbOpt(10)); // 89",
