        title: "Memoization vs Tabulation",
        simple: "Memoization (top-down): write the recursive solution, cache results in a map. Tabulation (bottom-up): fill a table iteratively from base cases up. Both are O(n) but tabulation avoids recursion overhead.",
        analogy: "Memoization is like a student solving problems on demand and writing answers in a notebook. Tabulation is like filling out a worksheet from question 1 to the last, in order.",
        whyItMatters: "Knowing both approaches lets you choose the right one. Memoization is easier to write; tabulation is faster and avoids stack overflow on large inputs.",
        code: "// Coin Change — minimum coins to make amount\n\n// Top-down (memoization)\nfunction coinChangeMemo(coins, amount) {\n  const memo = new Map();\n  function dp(rem) {\n    if (rem === 0) return 0;\n    if (rem < 0) return Infinity;\n    if (memo.has(rem)) return memo.get(rem);\n    let min = Infinity;\n    for (const c of coins) min = Math.min(min, 1 + dp(rem - c));\n    memo.set(rem, min);\n    return min;\n  }\n  const res = dp(amount);\n  return res === Infinity ? -1 : res;\n}\n\n// Bottom-up (tabulation)\nfunction coinChangeTab(coins, amount) {\n  const dp = new Array(amount + 1).fill(Infinity);\n  dp[0] = 0;\n  for (let i = 1; i <= amount; i++) {\n    for (const c of coins) {\n      if (c <= i) dp[i] = Math.min(dp[i], 1 + dp[i - c]);\n    }\n  }\n  return dp[amount] === Infinity ? -1 : dp[amount];\n}\n\nconsole.log(coinChangeTab([1,5,6,9], 11)); // 2 (5+6)",
        complexity: { time: "O(amount × coins)", space: "O(amount)" },
