        whyItMatters: "Knapsack is the template for many DP problems: partition equal subset sum, target sum, last stone weight II — all reduce to knapsack.",
        code: "function knapsack(weights, values, capacity) {\n  const n = weights.length;\n  // dp[i][w] = max value using first i items with capacity w\n  const dp = Array.from({length: n+1}, () => new Array(capacity+1).fill(0));\n\n  for (let i = 1; i <= n; i++) {\n    for (let w = 0; w <= capacity; w++) {\n      // Don't take item i\n      dp[i][w] = dp[i-1][w];\n      // Take item i (if it fits)\n      if (weights[i-1] <= w) {\n        dp[i][w] = Math.max(dp[i][w], values[i-1] + dp[i-1][w - weights[i-1]]);\n      }\n    }\n  }\n  return dp[n][capacity];\n}\n\nconsole.log(knapsack([2,3,4,5],[3,4,5,6], 5)); // 7\n\n// Space-optimized (1D dp)\nfunction knapsack1D(weights, values, capacity) {\n  const dp = new Array(capacity + 1).fill(0);\n  for (let i = 0; i < weights.length; i++)\n    for (let w = capacity; w >= weights[i]; w--) // iterate backwards!\n      dp[w] = Math.max(dp[w], values[i] + dp[w - weights[i]]);\n  return dp[capacity];\n}",
