        whyItMatters: "LCS is the foundation for: edit distance, shortest common supersequence, diff tools (git diff), and DNA sequence alignment.",
        code: "function lcs(s1, s2) {\n  const m = s1.length, n = s2.length;\n  // dp[i][j] = LCS length of s1[0..i-1] and s2[0..j-1]\n  const dp = Array.from({length: m+1}, () => new Array(n+1).fill(0));\n\n  for (let i = 1; i <= m; i++) {\n    for (let j = 1; j <= n; j++) {\n      if (s1[i-1] === s2[j-1]) {\n        dp[i][j] = 1 + dp[i-1][j-1]; // characters match\n      } else {\n        dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]); // take best\n      }\n    }\n  }\n  return dp[m][n];\n}\nconsole.log(lcs('abcde', 'ace')); // 3 (a,c,e)\nconsole.log(lcs('abc', 'abc'));   // 3\nconsole.log(lcs('abc', 'def'));   // 0\n\n// Edit Distance (Levenshtein)\nfunction editDistance(s1, s2) {\n  const m = s1.length, n = s2.length;\n  const dp = Array.from({length: m+1}, (_,i) => Array.from({length: n+1}, (_,j) => i||j));\n  for (let i=1;i<=m;i++)\n    for (let j=1;j<=n;j++)\n      dp[i][j] = s1[i-1]===s2[j-1] ? dp[i-1][j-1] : 1+Math.min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]);\n  return dp[m][n];\n}\nconsole.log(editDistance('horse','ros')); // 3",
