        code: "// Jump Game — can you reach the last index?\nfunction canJump(nums) {\n  let maxReach = 0;\n  for (let i = 0; i < nums.length; i++) {\n    if (i > maxReach) return false; // can't reach here\n    maxReach = Math.max(maxReach, i + nums[i]);\n  }\n  return true;\n}\nconsole.log(canJump([2,3,1,1,4])); // true\nconsole.log(canJump([3,2,1,0,4])); // false\n\n// Minimum number of platforms (meeting rooms)\nfunction minPlatforms(arrivals, departures) {\n  arrivals.sort((a,b) => a-b);\n  departures.sort((a,b) => a-b);\n  let platforms = 1, maxPlatforms = 1;\n  let i = 1, j = 0;\n  while (i < arrivals.length && j < departures.length) {\n    if (arrivals[i] <= departures[j]) { platforms++; i++; }\n    else { platforms--; j++; }\n    maxPlatforms = Math.max(maxPlatforms, platforms);\n  }\n  return maxPlatforms;\n}\nconsole.log(minPlatforms([900,940,950,1100,1500,1800],[910,1200,1120,1130,1900,2000])); // 3",
