        code: "class SegmentTree {\n  constructor(arr) {\n    this.n = arr.length;\n    this.tree = new Array(4 * this.n).fill(0);\n    this.build(arr, 0, 0, this.n - 1);\n  }\n\n  build(arr, node, start, end) {\n    if (start === end) {\n      this.tree[node] = arr[start];\n    } else {\n      const mid = (start + end) >> 1;\n      this.build(arr, 2*node+1, start, mid);\n      this.build(arr, 2*node+2, mid+1, end);\n      this.tree[node] = this.tree[2*node+1] + this.tree[2*node+2];\n    }\n  }\n\n  query(node, start, end, l, r) {\n    if (r < start || end < l) return 0; // out of range\n    if (l <= start && end <= r) return this.tree[node]; // fully in range\n    const mid = (start + end) >> 1;\n    return this.query(2*node+1, start, mid, l, r)\n         + this.query(2*node+2, mid+1, end, l, r);\n  }\n\n  rangeSum(l, r) { return this.query(0, 0, this.n-1, l, r); }\n}\n\nconst st = new SegmentTree([1,3,5,7,9,11]);\nconsole.log(st.rangeSum(1, 3)); // 15 (3+5+7)",
